concept.syntax:
// Lambda expression
val double: (Int) -> Int = { x -> x * 2 }
println(double(5))   // 10

// Single param: use 'it'
val square: (Int) -> Int = { it * it }

// Higher-order function
fun applyTwice(x: Int, f: (Int) -> Int): Int = f(f(x))
applyTwice(3, double)    // 12

// Trailing lambda
applyTwice(3) { it + 10 }  // 23

